import React from 'react';

const SearchField = ({
  label,
  name,
  value,
  onChange,
  placeholder,
  className,
  options, 
  disabled = false,
}) => {
  const isSelect = Array.isArray(options);

  return (
    <div className={`search-panel-inputs-items ${className}`}>
      <label htmlFor={name} className="input-label">
        {label}
      </label>

      {isSelect ? (
        <select
          id={name}
          name={name}
          value={value}
          onChange={onChange}
          disabled={disabled}
          className="home-search-panel-input"
        >
          <option value="">{placeholder}</option>
          {options.map((opt) => (
            <option key={opt} value={opt}>
              {opt}
            </option>
          ))}
        </select>
      ) : (
        <input
          id={name}
          name={name}
          value={value}
          onChange={onChange}
          placeholder={placeholder}
          className="home-search-panel-input"
        />
      )}
    </div>
  );
};

export default SearchField;
