import React, { useState } from "react";
import "../../../Styles/pages/SchoolSearchPanel.css";
import SearchField from "../../shared/Ui/SearchField";
const schoolData = [
  {
    name: "School Example One",
    options: [
      {
        name: "Best School",
        options: [
          { name: "Teacher One" },
          { name: "Teacher Two" },
        ],
      },
    ],
  },
  {
    name: "School Example Two",
    options: [
      {
        name: "Second Best School",
        options: [
          { name: "Teacher Three" },
          { name: "Teacher Four" },
        ],
      },
    ],
  },
];

function SchoolSearchPanel() {
  const [form, setForm] = useState({
    state: "",
    school: "",
    teacher: "",
  });

  // Get schools based on selected state
  const selectedState = schoolData.find((s) => s.name === form.state);
  const schools = selectedState?.options || [];

  // Get teachers based on selected school
  const selectedSchool = schools.find((s) => s.name === form.school);
  const teachers = selectedSchool?.options || [];

  const handleChange = (e) => {
    const { name, value } = e.target;

    // Reset dependent values if parent changes
    if (name === "state") {
      setForm({ state: value, school: "", teacher: "" });
    } else if (name === "school") {
      setForm({ ...form, school: value, teacher: "" });
    } else {
      setForm({ ...form, [name]: value });
    }
  };

  const handleSearch = () => {
    console.log("Searching with:", form);
    // Implement your search logic
  };

  return (
    <div className="home-school-panel-container">
      <div className="home-school-panel-inputs">

    <SearchField
  label="State"
  name="state"
  value={form.state}
  onChange={handleChange}
  placeholder="Select your state"
  options={schoolData.map((s) => s.name)}
/>

<SearchField
  label="School"
  name="school"
  value={form.school}
  onChange={handleChange}
  placeholder="Select your school"
  options={schools.map((s) => s.name)}
  disabled={!form.state}
/>

<SearchField
  label="Teacher"
  name="teacher"
  value={form.teacher}
  onChange={handleChange}
  placeholder="Select your teacher"
  options={teachers.map((t) => t.name)}
  disabled={!form.school}
/>


        {/* Search Button */}
        <div className="search-panel-inputs-items">
          <label htmlFor="button" className="search-label">Search</label>
          <button onClick={handleSearch} className="home-search-panel-button">
            Search
          </button>
        </div>

        {/* Help Text */}
        <p className="school-help-text">
          Don’t See Your School or Teacher? No problem!{" "}
          <a href="/support" className="school-help-link">
            Click here
          </a>{" "}
          to find out how we can help!
        </p>
      </div>
    </div>
  );
}

export default SchoolSearchPanel;
